public class WrapperDemo {
    public static void main(String[] args) {
        // ── Autoboxing ──────────────────────────────
        Integer a = 42;          // compiler: Integer.valueOf(42)
        int     b = a;           // compiler: a.intValue()
        System.out.println("a=" + a + ", b=" + b);

        // ── Cache trap: -128 to 127 reuses instances ──
        Integer x = 127; Integer y = 127;
        Integer p = 128; Integer q = 128;
        System.out.println("127 == 127: " + (x == y));  // true  (same cache object)
        System.out.println("128 == 128: " + (p == q));  // false (different objects)
        System.out.println("128 equals: " + p.equals(q)); // true

        // ── Utility methods ──────────────────────────
        System.out.println(Integer.MAX_VALUE);          // 2147483647
        System.out.println(Integer.toBinaryString(255)); // 11111111
        System.out.println(Integer.parseInt("FF", 16)); // 255

        // ── Unboxing NPE ─────────────────────────────
        Integer nullInt = null;
        try {
            int val = nullInt; // NullPointerException!
        } catch (NullPointerException e) {
            System.out.println("Unboxing null → NPE");
        }

        // ── Performance: avoid boxing in loops ────────
        long sum = 0;
        Long boxedSum = 0L; // BAD: creates Long each iteration
        for (int i = 0; i < 1_000; i++) {
            sum += i;       // primitive — no allocation
            boxedSum += i;  // creates new Long(boxedSum + i) each time!
        }
        System.out.println("sum=" + sum + ", boxedSum=" + boxedSum);
    }
}

public class EnumDemo {

    enum Day {
        MON(false), TUE(false), WED(false), THU(false), FRI(false),
        SAT(true), SUN(true);

        private final boolean weekend;
        Day(boolean weekend) { this.weekend = weekend; }
        public boolean isWeekend() { return weekend; }
    }

    enum Planet {
        MERCURY(3.303e+23, 2.4397e6),
        VENUS  (4.869e+24, 6.0518e6),
        EARTH  (5.976e+24, 6.37814e6);

        private final double mass;   // kg
        private final double radius; // metres
        Planet(double mass, double radius) { this.mass = mass; this.radius = radius; }
        static final double G = 6.67300E-11;
        double surfaceGravity() { return G * mass / (radius * radius); }
        double surfaceWeight(double earthWeight) {
            return earthWeight * surfaceGravity() / EARTH.surfaceGravity();
        }
    }

    public static void main(String[] args) {
        // Enum basics
        Day today = Day.WED;
        System.out.println(today.isWeekend()); // false
        System.out.println(today.name());      // WED
        System.out.println(today.ordinal());   // 2

        // Switch on enum (exhaustive in Java 14+)
        String type = switch (today) {
            case SAT, SUN -> "weekend";
            default       -> "weekday";
        };
        System.out.println(type);

        // Enum.values() iteration
        for (Day d : Day.values())
            if (d.isWeekend()) System.out.print(d + " ");
        System.out.println();

        // Enum.valueOf
        Day fri = Day.valueOf("FRI");
        System.out.println(fri.isWeekend()); // false

        // Planet weight on Mars (not in enum but shows pattern)
        double earthWeight = 75.0;
        System.out.printf("EARTH: %.2f%n", Planet.EARTH.surfaceWeight(earthWeight));
        System.out.printf("VENUS: %.2f%n", Planet.VENUS.surfaceWeight(earthWeight));
    }
}

