public class Q2 {
    enum DayType { WEEKDAY, WEEKEND }

    public static DayType classify(String day) {
        return switch (day.toUpperCase()) {
            case "SATURDAY", "SUNDAY" -> DayType.WEEKEND;
            case "MONDAY","TUESDAY","WEDNESDAY","THURSDAY","FRIDAY" -> DayType.WEEKDAY;
            default -> throw new IllegalArgumentException("Unknown day: " + day);
        };
    }
    public static void main(String[] args) {
        System.out.println(classify("Saturday")); // WEEKEND
        System.out.println(classify("Monday"));   // WEEKDAY
    }
}

