public class Q3 {
    public static void main(String[] args) {
        Integer a1 = 100, b1 = 100;
        System.out.println("100 == 100  ref: " + (a1 == b1));      // true  (cached)
        System.out.println("100 equals: " + a1.equals(b1));        // true

        Integer a2 = 200, b2 = 200;
        System.out.println("200 == 200  ref: " + (a2 == b2));      // false (not cached)
        System.out.println("200 equals: " + a2.equals(b2));        // true

        Integer a3 = Integer.valueOf(50), b3 = Integer.valueOf(50);
        System.out.println("50 valueOf ref: " + (a3 == b3));       // true  (cache)
    }
}
